273тЖТ}
274тЖТ.tab-switcher button.active {
275тЖТ  background: var(--primary); color: white;
276тЖТ  box-shadow: 0 0 10px var(--primary);
277тЖТ}
278тЖТ
279тЖТ/* тХРтХРтХР DIAG PANEL тХРтХРтХР */
280тЖТ.diag-panel { display: flex; flex-direction: column; gap: 1.25rem; margin-bottom: 2rem; }
281тЖТ.diag-item { display: flex; flex-direction: column; gap: 8px; }
282тЖТ.diag-label {
283тЖТ  font-size: 0.75rem; font-weight: 600; color: var(--text-muted);
284тЖТ  display: flex; justify-content: space-between;
285тЖТ}
286тЖТ.diag-label span { color: var(--text); font-family: monospace; }
287тЖТ.diag-bar-bg {
288тЖТ  height: 8px; background: rgba(255, 255, 255, 0.05);
289тЖТ  border-radius: 4px; overflow: hidden;
290тЖТ}
291тЖТ.diag-bar {
292тЖТ  height: 100%; border-radius: 4px;
293тЖТ  transition: width 0.5s ease-in-out;
294тЖТ}
295тЖТ.diag-bar.ram {
296тЖТ  background: linear-gradient(90deg, #38bdf8, #0ea5e9);
297тЖТ  box-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
298тЖТ}
299тЖТ.diag-bar.rom {
300тЖТ  background: linear-gradient(90deg, #a855f7, #8b5cf6);
301тЖТ  box-shadow: 0 0 10px rgba(168, 85, 247, 0.3);
302тЖТ}
303тЖТ
304тЖТ/* тХРтХРтХР MODAL тХРтХРтХР */
305тЖТ.modal-overlay {
306тЖТ  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
307тЖТ  background: rgba(0, 0, 0, 0.7); backdrop-filter: blur(4px);
308тЖТ  display: flex; align-items: center; justify-content: center;
309тЖТ  z-index: 100; padding: 1rem;
310тЖТ}
311тЖТ.modal-content {
312тЖТ  background: var(--bg-panel); border: 1px solid var(--panel-border);
313тЖТ  border-radius: 24px; padding: 2rem; width: 92%; max-width: 450px;
314тЖТ  max-height: 85vh; overflow-y: auto;
315тЖТ  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
316тЖТ}
317тЖТ@media (max-width: 768px) {
318тЖТ  .modal-overlay { padding: 0; align-items: flex-end; }
319тЖТ  .modal-content {
320тЖТ    width: 100%; max-width: 100%;
321тЖТ    border-radius: 24px 24px 0 0; padding: 1.25rem;
322тЖТ    max-height: 80vh; max-height: 80dvh;
323тЖТ  }
324тЖТ}
325тЖТ
326тЖТ/* тХРтХРтХР LOGIN тХРтХРтХР */
327тЖТ.login-page {
328тЖТ  display: flex; justify-content: center; align-items: center;
329тЖТ  height: 100vh; height: 100dvh;
330тЖТ  background: var(--bg);
331тЖТ  background-image: radial-gradient(circle at 50% 50%, #1e293b 0%, #05070a 100%);
332тЖТ  padding: 1rem;
333тЖТ}
334тЖТ.login-card {
335тЖТ  background: var(--bg-panel); border: 1px solid var(--panel-border);
336тЖТ  border-radius: 24px; padding: 2rem; width: 92%; max-width: 400px;
337тЖТ  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
338тЖТ}
339тЖТ@media (max-width: 768px) {
340тЖТ  .login-card { padding: 1.5rem; border-radius: 20px; width: 95%; }
341тЖТ}
342тЖТ.login-header { text-align: center; margin-bottom: 1.5rem; }
343тЖТ.login-icon {
344тЖТ  background: rgba(56, 189, 248, 0.1); width: 72px; height: 72px;
345тЖТ  border-radius: 18px; display: flex; align-items: center; justify-content: center;
346тЖТ  margin: 0 auto 1rem;
347тЖТ}
348тЖТ.login-title { font-size: 1.4rem; font-weight: 900; margin: 0; }
349тЖТ.login-subtitle { color: var(--text-muted); font-size: 0.85rem; margin: 4px 0 0; }
350тЖТ.login-error {
351тЖТ  background: rgba(239, 68, 68, 0.1); border: 1px solid rgba(239, 68, 68, 0.3);
352тЖТ  color: #ef4444; padding: 10px 14px; border-radius: 10px;
353тЖТ  font-size: 0.85rem; margin-bottom: 1rem; font-weight: 600;
354тЖТ}
355тЖТ.login-field { margin-bottom: 1rem; }
356тЖТ.login-field label {
357тЖТ  display: block; font-size: 0.75rem; font-weight: 600;
358тЖТ  color: var(--text-muted); margin-bottom: 6px; text-transform: uppercase;
359тЖТ  letter-spacing: 0.5px;
360тЖТ}
361тЖТ.login-field input {
362тЖТ  width: 100%; padding: 12px 16px; background: rgba(255, 255, 255, 0.05);
363тЖТ  border: 1px solid var(--panel-border); border-radius: 12px;
364тЖТ  color: var(--text-main); font-size: 16px; outline: none; transition: 0.2s;
365тЖТ}
366тЖТ.login-field input:focus {
367тЖТ  border-color: var(--primary);
368тЖТ  box-shadow: 0 0 0 2px rgba(0, 210, 255, 0.2);
369тЖТ}
370тЖТ.login-btn { margin-top: 0.5rem; }
371тЖТ
372тЖТ/* тХРтХРтХР FORM ELEMENTS тХРтХРтХР */
373тЖТ.input-field {
374тЖТ  width: 100%; padding: 12px 16px;
375тЖТ  background: rgba(255, 255, 255, 0.05);
376тЖТ  border: 1px solid var(--panel-border); border-radius: 12px;
377тЖТ  color: var(--text-main); font-size: 1rem; margin-bottom: 1rem;
378тЖТ  outline: none; transition: 0.2s;
379тЖТ}
380тЖТ.input-field:focus {
381тЖТ  border-color: var(--primary);
382тЖТ  box-shadow: 0 0 0 2px rgba(0, 210, 255, 0.2);
383тЖТ}
384тЖТ@media (max-width: 768px) {
385тЖТ  .input-field {
386тЖТ    padding: 10px 14px; font-size: 16px;
387тЖТ    border-radius: 10px; margin-bottom: 0.75rem;
388тЖТ  }
389тЖТ}
390тЖТ.btn-submit {
391тЖТ  width: 100%; padding: 14px; background: var(--primary);
392тЖТ  color: #0a0f1a; border: none; border-radius: 12px;
393тЖТ  font-size: 1rem; font-weight: 800; cursor: pointer;
394тЖТ  transition: 0.2s; touch-action: manipulation;
395тЖТ}
396тЖТ.btn-submit:hover { filter: brightness(1.1); transform: translateY(-1px); }
397тЖТ.btn-submit:active { transform: scale(0.98); }
398тЖТ@media (max-width: 768px) {
399тЖТ  .btn-submit { padding: 12px; font-size: 0.9rem; border-radius: 10px; }
400тЖТ}
401тЖТ
402тЖТ/* тХРтХРтХР ANIMATIONS тХРтХРтХР */
403тЖТ@keyframes shuttle-anim {
404тЖТ  0% { transform: translateX(-5px); }
405тЖТ  50% { transform: translateX(5px); }
406тЖТ  100% { transform: translateX(-5px); }
407тЖТ}
408тЖТ.shuttle-anim { animation: shuttle-anim 0.5s linear infinite; }
409тЖТ.pulse-neon { position: relative; }
410тЖТ.pulse-neon::after {
411тЖТ  content: ''; position: absolute;
412тЖТ  top: -2px; left: -2px; right: -2px; bottom: -2px;
413тЖТ  border-radius: 12px; border: 1px solid var(--neon-green);
414тЖТ  opacity: 0; animation: ripple 2s infinite;
415тЖТ}
416тЖТ@keyframes ripple {
417тЖТ  0% { transform: scale(1); opacity: 0.5; }
418тЖТ  100% { transform: scale(1.5); opacity: 0; }
419тЖТ}
420тЖТ@keyframes pulse {
421тЖТ  0% { transform: scale(1); }
422тЖТ  50% { transform: scale(1.15); }
423тЖТ  100% { transform: scale(1); }
424тЖТ}
425тЖТ@keyframes slideIn {
426тЖТ  0% { opacity: 0; transform: translateY(-10px); }
427тЖТ  100% { opacity: 1; transform: translateY(0); }
428тЖТ}
429тЖТ.chiqish-label {
430тЖТ  position: absolute; background: #22c55e;
431тЖТ  padding: 4px 12px; border-radius: 6px;
432тЖТ  font-size: 0.65rem; font-weight: 800; color: #064e3b;
433тЖТ  box-shadow: 0 0 10px rgba(34, 197, 94, 0.3);
434тЖТ}
